// === BBOX UNIÓN + ARRAY DE POLÍGONOS ===
const items = $input.all();

if (items.length === 0) {
  throw new Error('No hay polígonos activos. Verificar zonas_geograficas o array de zonas en query SQL.');
}

let minLat = Infinity, maxLat = -Infinity;
let minLon = Infinity, maxLon = -Infinity;
const polygons = [];

for (const item of items) {
  const data = item.json;
  minLat = Math.min(minLat, parseFloat(data.lat_sur));
  maxLat = Math.max(maxLat, parseFloat(data.lat_norte));
  minLon = Math.min(minLon, parseFloat(data.lon_oeste));
  maxLon = Math.max(maxLon, parseFloat(data.lon_este));

  const geo = JSON.parse(data.geom_geojson);
  polygons.push({
    nombre: data.nombre,
    coordinates: geo.coordinates[0]
  });
}

console.log(`BBox: lat ${minLat} → ${maxLat}, lon ${minLon} → ${maxLon}`);
console.log(`Polígonos: ${polygons.map(p => p.nombre).join(', ')}`);

return [{
  json: {
    bbox: { lat_sur: minLat, lat_norte: maxLat, lon_oeste: minLon, lon_este: maxLon },
    polygons,
    zonas_incluidas: items.map(i => i.json.nombre)
  }
}];

// === GENERADOR DE URLs REMAX (endpoint base SC sin slug) ===
// Trae TODO Santa Cruz paginado (venta + alquiler mezclados).
// El filtro de operación (alquiler) y el filtro por polígono se aplican post-fetch.
// Cobertura validada en PoC 20-may-2026: ~517 props en 30 páginas. Margen: 30 páginas fijas.

const TOTAL_PAGES = 30;
const BASE_URL = 'https://remax.bo/api/search/departamento/santa-cruz-de-la-sierra';

const urls = [];
for (let page = 1; page <= TOTAL_PAGES; page++) {
  urls.push({
    json: {
      page_url: `${BASE_URL}?page=${page}`,
      page_number: page,
      fuente: 'remax'
    }
  });
}

console.log(`URLs generadas: ${urls.length} páginas para todo SC. Filtro alquiler + polígono post-fetch.`);
return urls;

// === EXTRAER PROPIEDADES REMAX (ALQUILER ZONA NORTE) ===
// Extrae TODAS las props de la página (venta + alquiler). El filtrado de
// operación se hace en 'Filtrar Solo Alquileres' y el geográfico en
// 'Filtrar por Polígonos'. Cada prop trae lat/lon (para el polígono),
// transaction_type (para el filtro alquiler) y precio crudo BOB + USD
// + moneda_original (para la conversión en 'Procesar Alquileres').
const response = $input.first().json;
const propiedades = response.data || [];

if (propiedades.length === 0) {
  return [];
}

return propiedades.map(prop => ({
  json: {
    url: `https://remax.bo/propiedad/${prop.slug}`,
    fuente: 'remax',
    codigo_propiedad: prop.MLSID,
    tipo_operacion: prop.transaction_type?.name?.toLowerCase() || null,
    latitud: parseFloat(prop.location?.latitude) || null,
    longitud: parseFloat(prop.location?.longitude) || null,
    precio_bob: prop.price?.amount || null,
    precio_usd: prop.price?.price_in_dollars || null,
    moneda_original: prop.price?.currency_id === 1 ? 'BOB' : 'USD',
    area_total_m2: prop.listing_information?.construction_area_m || null,
    dormitorios: prop.listing_information?.number_bedrooms || null,
    banos: prop.listing_information?.number_bathrooms || null,
    estacionamientos: prop.listing_information?.number_parking || null,
    tipo_propiedad_original: prop.listing_information?.subtype_property?.name || null,
    fecha_publicacion: prop.date_of_listing || null,
    datos_json_discovery: prop,
    metodo_discovery: 'zonanorte_remax_alquiler'
  }
}));

// === FILTRAR SOLO ALQUILERES ===
// La API Remax (endpoint todo-SC) devuelve venta + alquiler mezclados.
// Filtramos por transaction_type que contenga 'alquiler', 'arriendo' o 'renta'.
// Excluimos venta y anticrético (modelo financiero distinto).
// Se ejecuta ANTES del filtro geográfico (primero operación, luego polígono).

const snapshot = $input.first().json.propiedades || [];

const alquileres = snapshot.filter(prop => {
  const tipo = (prop.tipo_operacion || '').toLowerCase();
  return tipo.includes('alquiler') || tipo.includes('arriendo') || tipo.includes('renta');
});

const excluidos = snapshot.length - alquileres.length;

console.log(`Filtro alquiler: ${alquileres.length} alquileres de ${snapshot.length} total (${excluidos} excluidos)`);

return [{
  json: {
    propiedades: alquileres,
    stats_filtro: {
      total_api: snapshot.length,
      alquileres: alquileres.length,
      excluidos: excluidos
    }
  }
}];

// === FILTRO POINT-IN-POLYGON ===
function pointInPolygon(lon, lat, ring) {
  let inside = false;
  for (let i = 0, j = ring.length - 1; i < ring.length; j = i++) {
    const xi = ring[i][0], yi = ring[i][1];
    const xj = ring[j][0], yj = ring[j][1];
    const intersect = ((yi > lat) !== (yj > lat)) &&
      (lon < (xj - xi) * (lat - yi) / (yj - yi) + xi);
    if (intersect) inside = !inside;
  }
  return inside;
}

const polygons = $('Calcular BBox + Polígonos').first().json.polygons || [];
if (polygons.length === 0) {
  console.warn('Sin polígonos activos — devuelvo vacío (FAIL CLOSED)');
  return [{ json: { propiedades: [], stats: { total: 0, dentro: 0, fuera: 0 } } }];
}

const input = $input.first().json;
const propiedades = input.propiedades || [];

const dentro = propiedades.filter(p => {
  const lat = parseFloat(p.latitud);
  const lon = parseFloat(p.longitud);
  if (!Number.isFinite(lat) || !Number.isFinite(lon)) return false;
  return polygons.some(poly => pointInPolygon(lon, lat, poly.coordinates));
});

console.log(`Filtro polígono: ${dentro.length}/${propiedades.length} dentro de [${polygons.map(p => p.nombre).join(', ')}]`);

return [{
  json: {
    propiedades: dentro,
    stats: { total: propiedades.length, dentro: dentro.length, fuera: propiedades.length - dentro.length }
  }
}];

// === PREPARAR COMPARACIÓN ===
const snapshot = $('Filtrar por Polígonos').first().json.propiedades || [];
const propiedadesBD = $('Obtener URLs Activas BD').all().map(item => item.json);

const snapshotDedup = new Map();
for (const prop of snapshot) {
  snapshotDedup.set(prop.url, prop);
}

const urlsSnapshot = new Set(snapshotDedup.keys());
const urlsBD = new Map(propiedadesBD.map(p => [p.url, { id: p.id, status: p.status }]));

const nuevas = [];
const existentes = [];
const ausentes = [];

for (const [url, prop] of snapshotDedup) {
  if (!urlsBD.has(url)) {
    nuevas.push(prop);
  } else {
    existentes.push({
      ...prop,
      _id_bd: urlsBD.get(url).id,
      _status_bd: urlsBD.get(url).status
    });
  }
}

for (const [url, info] of urlsBD) {
  if (!urlsSnapshot.has(url)) {
    if (!['inactivo_pending', 'inactivo_confirmed'].includes(info.status)) {
      ausentes.push({
        id: info.id,
        url: url,
        status_actual: info.status
      });
    }
  }
}

return [{
  json: {
    nuevas,
    existentes,
    ausentes,
    stats: {
      total_snapshot: snapshotDedup.size,
      total_bd: urlsBD.size,
      nuevas: nuevas.length,
      existentes: existentes.length,
      ausentes: ausentes.length
    }
  }
}];

// === LOG STATS ===
const stats = $input.first().json.stats;
const filtro = $('Filtrar Solo Alquileres').first().json.stats_filtro;

console.log(`
=== DISCOVERY REMAX ALQUILER ZONA NORTE ===
API total (venta+alquiler): ${filtro.total_api}
Alquileres filtrados: ${filtro.alquileres}
Excluidos (venta/antic): ${filtro.excluidos}
---
Snapshot dentro polígono (deduplicado): ${stats.total_snapshot}
BD activas (zonas activas): ${stats.total_bd}
Nuevas: ${stats.nuevas}
Existentes: ${stats.existentes}
Ausentes: ${stats.ausentes}
===========================================
`);

return $input.all();

// === PREPARAR PARA registrar_discovery_alquiler() ===
// Fix 2 Apr 2026: convertir USD↔BOB según moneda_original (bug: 26 props mostraban USD como BOB)
const data = $input.first().json;
const nuevas = data.nuevas || [];
const existentes = data.existentes || [];
const todas = [...nuevas, ...existentes];

if (todas.length === 0) {
  return [{ json: { skip: true, message: 'No hay alquileres para procesar' } }];
}

return todas.map(prop => ({
  json: {
    p_url: prop.url,
    p_fuente: prop.fuente,
    p_codigo_propiedad: prop.codigo_propiedad,
    p_precio_mensual_bob: prop.moneda_original === 'USD'
        ? Math.round(prop.precio_usd * 6.96)
        : prop.precio_bob,
    p_precio_mensual_usd: prop.moneda_original === 'BOB'
        ? Math.round(prop.precio_bob / 6.96 * 100) / 100
        : prop.precio_usd,
    p_moneda_original: prop.moneda_original || 'BOB',
    p_area_total_m2: prop.area_total_m2,
    p_dormitorios: prop.dormitorios,
    p_banos: prop.banos,
    p_estacionamientos: prop.estacionamientos,
    p_tipo_propiedad_original: prop.tipo_propiedad_original,
    p_latitud: prop.latitud,
    p_longitud: prop.longitud,
    p_fecha_publicacion: prop.fecha_publicacion,
    p_metodo_discovery: prop.metodo_discovery,
    p_zona: null,
    p_datos_json_discovery: JSON.stringify(prop.datos_json_discovery)
  }
}));

// === PROCESAR AUSENTES ===
const ausentes = $input.first().json.ausentes;

if (ausentes.length === 0) {
  return [{ json: { skip: true, message: 'No hay alquileres ausentes' } }];
}

return ausentes.map(prop => ({
  json: {
    id: prop.id,
    url: prop.url,
    status_actual: prop.status_actual
  }
}));

// === RESUMEN FINAL ===
const stats = $('Log Stats').first().json.stats;
const filtro = $('Filtrar Solo Alquileres').first().json.stats_filtro;
const zonas = $('Calcular BBox + Polígonos').first().json.zonas_incluidas;

const resumen = {
  timestamp: new Date().toISOString(),
  fuente: 'remax',
  workflow: 'Discovery Remax Alquiler Zona Norte',
  version: '1.0.0',
  zonas_activas: zonas,
  resultados: {
    api_total: filtro.total_api,
    alquileres_filtrados: filtro.alquileres,
    excluidos_venta: filtro.excluidos,
    snapshot_total: stats.total_snapshot,
    bd_activas: stats.total_bd,
    nuevas_insertadas: stats.nuevas,
    existentes_actualizadas: stats.existentes,
    ausentes_marcadas: stats.ausentes
  },
  status: 'completado'
};

console.log('=== DISCOVERY REMAX ALQUILER ZONA NORTE COMPLETADO ===');
console.log(JSON.stringify(resumen, null, 2));

return [{ json: resumen }];
